import React, { useState } from 'react';
import {
  Box,
  Paper,
  Typography,
  TextField,
  Select,
  MenuItem,
  Chip,
  Button,
  Checkbox,
  FormControlLabel,
  Modal,
  Divider,
  Alert,
} from '@mui/material';
import { motion } from 'framer-motion';
import { useNavigate } from 'react-router-dom';
import { PlusIcon, SparklesIcon } from '@heroicons/react/24/outline';

const CreateJob: React.FC = () => {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    jobTitle: '',
    department: '',
    description: '',
    skills: [] as string[],
    customQuestions: '',
    questionTemplate: '',
    numQuestions: 5,
    aiScoreThreshold: 80,
    postToLinkedIn: false,
    postToIndeed: false,
    geminiApiKey: '',
  });
  const [newSkill, setNewSkill] = useState('');
  const [error, setError] = useState('');
  const [modalOpen, setModalOpen] = useState(false);
  const [loadingAI, setLoadingAI] = useState(false);

  const departments = ['Engineering', 'Marketing', 'Sales', 'Operations', 'HR'];
  const questionTemplates = ['Technical Interview', 'Behavioral Interview', 'General'];

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  const handleSelectChange = (e: any) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  const handleSkillAdd = () => {
    if (newSkill && !formData.skills.includes(newSkill)) {
      setFormData({ ...formData, skills: [...formData.skills, newSkill] });
      setNewSkill('');
    }
  };

  const handleSkillDelete = (skill: string) => {
    setFormData({ ...formData, skills: formData.skills.filter((s) => s !== skill) });
  };

  const handleCheckboxChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, checked } = e.target;
    setFormData({ ...formData, [name]: checked });
  };

  const generateAIQuestions = async () => {
    if (!formData.geminiApiKey) {
      setError('Please provide a Gemini API key');
      return;
    }
    if (!formData.jobTitle) {
      setError('Please enter a job title to generate questions');
      return;
    }

    setLoadingAI(true);
    setError('');
    try {
      // Mock Gemini API call
      const mockQuestions = `1. What experience do you have with ${formData.jobTitle} responsibilities?\n2. How would you handle a challenging project in ${formData.jobTitle}?\n3. Describe a time you improved a process related to ${formData.jobTitle}.`;
      setFormData({ ...formData, customQuestions: mockQuestions });
    } catch (err) {
      setError('Failed to generate AI questions. Please check your API key.');
    } finally {
      setLoadingAI(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!formData.jobTitle || !formData.department || !formData.description) {
      setError('Job Title, Department, and Description are required');
      return;
    }

    // Mock job creation
    console.log('Creating job:', formData);
    setModalOpen(true);
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: { opacity: 1, transition: { staggerChildren: 0.1 } },
  };

  const childVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { opacity: 1, y: 0 },
  };

  const buttonVariants = {
    hover: { scale: 1.05, boxShadow: '0px 0px 20px rgba(59, 130, 246, 0.5)' },
    tap: { scale: 0.95 },
  };

  return (
    <Box
      sx={{
        minHeight: '100vh',
        bgcolor: '#0a0f24',
        background: 'radial-gradient(circle at center, #1e3a8a 0%, #0a0f24 100%)',
        pt: 10,
        px: 4,
        position: 'relative',
        overflow: 'hidden',
        '&:before': {
          content: '""',
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          background: 'linear-gradient(45deg, rgba(59,130,246,0.1) 0%, rgba(147,51,234,0.1) 100%)',
          animation: 'pulse 8s infinite',
        },
      }}
    >
      <style>
        {`
          @keyframes pulse {
            0% { opacity: 0.3; }
            50% { opacity: 0.6; }
            100% { opacity: 0.3; }
          }
        `}
      </style>
      <motion.div variants={containerVariants} initial="hidden" animate="visible">
        <Paper
          elevation={12}
          sx={{
            p: 4,
            maxWidth: 800,
            mx: 'auto',
            bgcolor: 'rgba(15, 23, 42, 0.95)',
            border: '1px solid rgba(59, 130, 246, 0.3)',
            borderRadius: 4,
            boxShadow: '0 0 40px rgba(59, 130, 246, 0.2)',
          }}
        >
          <motion.div variants={childVariants}>
            <Typography
              variant="h4"
              sx={{
                mb: 4,
                color: '#3b82f6',
                background: 'linear-gradient(45deg, #3b82f6, #9333ea)',
                WebkitBackgroundClip: 'text',
                WebkitTextFillColor: 'transparent',
                fontWeight: 'bold',
                textAlign: 'center',
              }}
            >
              Create New Job Listing
            </Typography>
          </motion.div>

          {error && (
            <motion.div variants={childVariants}>
              <Alert severity="error" sx={{ mb: 3, bgcolor: 'rgba(239, 68, 68, 0.1)', color: '#ef4444' }}>
                {error}
              </Alert>
            </motion.div>
          )}

          <form onSubmit={handleSubmit}>
            <motion.div variants={childVariants}>
              <TextField
                fullWidth
                label="Job Title"
                name="jobTitle"
                value={formData.jobTitle}
                onChange={handleInputChange}
                required
                sx={textFieldStyles}
              />
            </motion.div>
            <motion.div variants={childVariants}>
              <Select
                fullWidth
                name="department"
                value={formData.department}
                onChange={handleSelectChange}
                displayEmpty
                sx={{
                  mt: 3,
                  bgcolor: 'rgba(30, 41, 59, 0.5)',
                  color: '#e2e8f0',
                  '& .MuiSelect-select': { py: 1.5 },
                  '& .MuiOutlinedInput-notchedOutline': { borderColor: 'rgba(59, 130, 246, 0.3)' },
                  '&:hover .MuiOutlinedInput-notchedOutline': { borderColor: '#3b82f6' },
                  '&.Mui-focused .MuiOutlinedInput-notchedOutline_means': {
                    borderColor: '#3b82f6',
                    boxShadow: '0 0 10px rgba(59, 130, 246, 0.3)',
                  },
                }}
              >
                <MenuItem value="" disabled>
                  Select Department
                </MenuItem>
                {departments.map((dept) => (
                  <MenuItem key={dept} value={dept}>
                    {dept}
                  </MenuItem>
                ))}
              </Select>
            </motion.div>
            <motion.div variants={childVariants}>
              <TextField
                fullWidth
                label="Description"
                name="description"
                value={formData.description}
                onChange={handleInputChange}
                multiline
                rows={4}
                required
                sx={{ ...textFieldStyles, mt: 3 }}
              />
            </motion.div>
            <motion.div variants={childVariants}>
              <Box sx={{ mt: 3 }}>
                <TextField
                  fullWidth
                  label="Skills / Keywords"
                  value={newSkill}
                  onChange={(e) => setNewSkill(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && handleSkillAdd()}
                  sx={textFieldStyles}
                  InputProps={{
                    endAdornment: (
                      <Button
                        onClick={handleSkillAdd}
                        sx={{ color: '#3b82f6', textTransform: 'none' }}
                      >
                        Add
                      </Button>
                    ),
                  }}
                />
                <Box sx={{ mt: 2, display: 'flex', flexWrap: 'wrap', gap: 1 }}>
                  {formData.skills.map((skill) => (
                    <Chip
                      key={skill}
                      label={skill}
                      onDelete={() => handleSkillDelete(skill)}
                      sx={{
                        bgcolor: 'rgba(59, 130, 246, 0.2)',
                        color: '#e2e8f0',
                        '&:hover': { bgcolor: 'rgba(59, 130, 246, 0.4)' },
                      }}
                    />
                  ))}
                </Box>
              </Box>
            </motion.div>
            <motion.div variants={childVariants}>
              <Box sx={{ mt: 3 }}>
                <TextField
                  fullWidth
                  label="Gemini API Key"
                  name="geminiApiKey"
                  value={formData.geminiApiKey}
                  onChange={handleInputChange}
                  sx={textFieldStyles}
                />
                <Button
                  component={motion.button}
                  variants={buttonVariants}
                  whileHover="hover"
                  whileTap="tap"
                  onClick={generateAIQuestions}
                  disabled={loadingAI}
                  startIcon={<SparklesIcon className="h-5 w-5" />}
                  sx={{
                    mt: 2,
                    bgcolor: 'rgba(59, 130, 246, 0.2)',
                    color: '#3b82f6',
                    textTransform: 'none',
                    '&:hover': {
                      bgcolor: 'rgba(59, 130, 246, 0.4)',
                      boxShadow: '0 0 10px rgba(59, 130, 246, 0.3)',
                    },
                  }}
                >
                  {loadingAI ? 'Generating...' : 'Generate AI Questions'}
                </Button>
              </Box>
            </motion.div>
            <motion.div variants={childVariants}>
              <TextField
                fullWidth
                label="Custom Questions"
                name="customQuestions"
                value={formData.customQuestions}
                onChange={handleInputChange}
                multiline
                rows={4}
                sx={{ ...textFieldStyles, mt: 3 }}
              />
            </motion.div>
            <motion.div variants={childVariants}>
              <Select
                fullWidth
                name="questionTemplate"
                value={formData.questionTemplate}
                onChange={handleSelectChange}
                displayEmpty
                sx={{
                  mt: 3,
                  bgcolor: 'rgba(30, 41, 59, 0.5)',
                  color: '#e2e8f0',
                  '& .MuiSelect-select': { py: 1.5 },
                  '& .MuiOutlinedInput-notchedOutline': { borderColor: 'rgba(59, 130, 246, 0.3)' },
                  '&:hover .MuiOutlinedInput-notchedOutline': { borderColor: '#3b82f6' },
                  '&.Mui-focused .MuiOutlinedInput-notchedOutline': {
                    borderColor: '#3b82f6',
                    boxShadow: '0 0 10px rgba(59, 130, 246, 0.3)',
                  },
                }}
              >
                <MenuItem value="" disabled>
                  Select Question Template (Optional)
                </MenuItem>
                {questionTemplates.map((template) => (
                  <MenuItem key={template} value={template}>
                    {template}
                  </MenuItem>
                ))}
              </Select>
            </motion.div>
            <motion.div variants={childVariants}>
              <TextField
                fullWidth
                label="Number of Interview Questions"
                name="numQuestions"
                type="number"
                value={formData.numQuestions}
                onChange={handleInputChange}
                inputProps={{ min: 1 }}
                sx={{ ...textFieldStyles, mt: 3 }}
              />
            </motion.div>
            <motion.div variants={childVariants}>
              <TextField
                fullWidth
                label="AI Score Threshold (%)"
                name="aiScoreThreshold"
                type="number"
                value={formData.aiScoreThreshold}
                onChange={handleInputChange}
                inputProps={{ min: 0, max: 100 }}
                sx={{ ...textFieldStyles, mt: 3 }}
              />
            </motion.div>
            <motion.div variants={childVariants}>
              <Box sx={{ mt: 3 }}>
                <FormControlLabel
                  control={
                    <Checkbox
                      name="postToLinkedIn"
                      checked={formData.postToLinkedIn}
                      onChange={handleCheckboxChange}
                      sx={{ color: '#3b82f6', '&.Mui-checked': { color: '#3b82f6' } }}
                    />
                  }
                  label="Post to LinkedIn"
                  sx={{ color: '#e2e8f0' }}
                />
                <FormControlLabel
                  control={
                    <Checkbox
                      name="postToIndeed"
                      checked={formData.postToIndeed}
                      onChange={handleCheckboxChange}
                      sx={{ color: '#3b82f6', '&.Mui-checked': { color: '#3b82f6' } }}
                    />
                  }
                  label="Post to Indeed"
                  sx={{ color: '#e2e8f0' }}
                />
              </Box>
            </motion.div>
            <motion.div variants={childVariants}>
              <Button
                component={motion.button}
                variants={buttonVariants}
                whileHover="hover"
                whileTap="tap"
                type="submit"
                fullWidth
                variant="contained"
                sx={{
                  mt: 4,
                  py: 1.5,
                  background: 'linear-gradient(45deg, #3b82f6, #9333ea)',
                  '&:hover': {
                    background: 'linear-gradient(45deg, #2563eb, #7e22ce)',
                    boxShadow: '0 0 20px rgba(59, 130, 246, 0.5)',
                  },
                  textTransform: 'none',
                  fontWeight: 'bold',
                }}
              >
                Create Job
              </Button>
            </motion.div>
          </form>
        </Paper>
      </motion.div>

      {/* Success Modal */}
      <Modal open={modalOpen} onClose={() => setModalOpen(false)}>
        <Box
          sx={{
            position: 'absolute',
            top: '50%',
            left: '50%',
            transform: 'translate(-50%, -50%)',
            width: 500,
            bgcolor: 'rgba(15, 23, 42, 0.95)',
            border: '1px solid rgba(59, 130, 246, 0.3)',
            borderRadius: 4,
            p: 4,
            boxShadow: '0 0 40px rgba(59, 130, 246, 0.2)',
          }}
        >
          <Typography
            variant="h5"
            sx={{
              color: '#3b82f6',
              background: 'linear-gradient(45deg, #3b82f6, #9333ea)',
              WebkitBackgroundClip: 'text',
              WebkitTextFillColor: 'transparent',
              mb: 3,
            }}
          >
            Job Created Successfully
          </Typography>
          <Typography variant="body1" color="#e2e8f0" sx={{ mb: 2 }}>
            <strong>Job Title:</strong> {formData.jobTitle}
          </Typography>
          <Typography variant="body1" color="#e2e8f0" sx={{ mb: 2 }}>
            <strong>Department:</strong> {formData.department}
          </Typography>
          <Typography variant="body1" color="#e2e8f0" sx={{ mb: 2 }}>
            <strong>Posting:</strong>{' '}
            {formData.postToLinkedIn && formData.postToIndeed
              ? 'LinkedIn, Indeed'
              : formData.postToLinkedIn
              ? 'LinkedIn'
              : formData.postToIndeed
              ? 'Indeed'
              : 'Not posted'}
          </Typography>
          <Divider sx={{ my: 2, bgcolor: 'rgba(59, 130, 246, 0.2)' }} />
          <Typography variant="h6" color="#3b82f6" sx={{ mb: 2 }}>
            Next Steps
          </Typography>
          <Box component="ol" sx={{ pl: 3, color: '#e2e8f0' }}>
            <li>
              <Typography variant="body2">
                <strong>Job Creation:</strong> Job listing has been created and saved.
              </Typography>
            </li>
            <li>
              <Typography variant="body2">
                <strong>AI Analysis:</strong> HUNTER AI will analyze applications using configured metrics.
              </Typography>
            </li>
            <li>
              <Typography variant="body2">
                <strong>Posting:</strong> Job will be posted to selected platforms (if any).
              </Typography>
            </li>
            <li>
              <Typography variant="body2">
                <strong>Candidate Review:</strong> Monitor applications in the Candidates dashboard.
              </Typography>
            </li>
          </Box>
          <Button
            component={motion.button}
            variants={buttonVariants}
            whileHover="hover"
            whileTap="tap"
            onClick={() => {
              setModalOpen(false);
              navigate('/jobs');
            }}
            fullWidth
            sx={{
              mt: 3,
              py: 1.5,
              background: 'linear-gradient(45deg, #3b82f6, #9333ea)',
              '&:hover': {
                background: 'linear-gradient(45deg, #2563eb, #7e22ce)',
                boxShadow: '0 0 20px rgba(59, 130, 246, 0.5)',
              },
              textTransform: 'none',
              fontWeight: 'bold',
            }}
          >
            Go to Jobs
          </Button>
        </Box>
      </Modal>
    </Box>
  );
};

// Reusable TextField styles
const textFieldStyles = {
  mt: 3,
  '& .MuiOutlinedInput-root': {
    bgcolor: 'rgba(30, 41, 59, 0.5)',
    color: '#e2e8f0',
    borderRadius: 2,
    '& fieldset': { borderColor: 'rgba(59, 130, 246, 0.3)' },
    '&:hover fieldset': { borderColor: '#3b82f6' },
    '&.Mui-focused fieldset': {
      borderColor: '#3b82f6',
      boxShadow: '0 0 10px rgba(59, 130, 246, 0.3)',
    },
  },
  '& .MuiInputLabel-root': { color: '#94a3b8' },
  '& .MuiInputLabel-root.Mui-focused': { color: '#3b82f6' },
};

export default CreateJob;
